SELECT campaign_id, SUM(budget) AS total_budget
FROM vaccination_campaigns
GROUP BY campaign_id;

SELECT SUM(dose_number) AS total_doses
FROM doses_administered
WHERE administered_by = 'Dr. Smith';

SELECT *
FROM vaccination_types
WHERE vaccine_id = 0;

SELECT c.county_name, c.population_density, v.vaccine_name, v.manufacturer
FROM counties c
CROSS JOIN vaccination_types v;
